import React, { useState } from 'react'; 
import axios from 'axios'; 
const AdminUpload = () => { 
  const [title, setTitle] = useState(''); 
  const [artist, setArtist] = useState(''); 
  const [songFile, setSongFile] = useState(null); 
  const [imageFile, setImageFile] = useState(null); 
  const [loading, setLoading] = useState(false); 
 
  const handleUpload = async (e) => { 
    e.preventDefault(); 
    setLoading(true); 
    const formData = new FormData(); 
    formData.append('title', title); 
    formData.append('artist', artist); 
    formData.append('song', songFile); 
    formData.append('image', imageFile); 
    try { 
      await axios.post('http://localhost:5000/api/songs/upload', formData); 
      alert('Tải lên thành công!'); 
      window.location.href = '/'; 
    } catch (err) { alert('Lỗi khi tải lên!'); } 
    setLoading(false); 
  }; 
 
  return ( 
    <div style={{ padding: '40px', maxWidth: '500px', margin: '50px auto', background: '#fff', borderRadius: '15px', boxShadow: '0 5px 20px rgba(0,0,0,0.1)' }}> 
      <h2 style={{ textAlign: 'center', color: '#1db954' }}>TẢI NHẠC MỚI</h2> 
      <form onSubmit={handleUpload} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}> 
        <input type="text" placeholder="Tên bài hát" onChange={e => setTitle(e.target.value)} required style={inputStyle} /> 
        <input type="text" placeholder="Ca sĩ" onChange={e => setArtist(e.target.value)} required style={inputStyle} /> 
        <label>File nhạc (mp3):</label><input type="file" accept="audio/*" onChange={e => setSongFile(e.target.files[0])} required /> 
        <label>Ảnh bìa (jpg/png):</label><input type="file" accept="image/*" onChange={e => setImageFile(e.target.files[0])} required /> 
        <button type="submit" disabled={loading} style={{ padding: '12px', background: '#1db954', color: 'white', border: 'none', borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold' }}> 
          {loading ? 'Đang tải lên...' : 'XÁC NHẬN UPLOAD'} 
        </button> 
      </form> 
    </div> 
  ); 
}; 
const inputStyle = { padding: '10px', borderRadius: '5px', border: '1px solid #ddd' }; 
export default AdminUpload;
